  "Dashboards/Signups by region.vl.json": "{\n  \"lattice\": {\n    \"data\": {\n      \"dataset\": \"Data/Events.dataset\",\n      \"sql\": \"SELECT region, sum(signups) AS signups FROM read_parquet('Data/Events.dataset/facts/**/*.parquet', hive_partitioning = true, union_by_name = true) GROUP BY region ORDER BY region\"\n    }\n  },\n  \"$schema\": \"https://vega.github.io/schema/vega-lite/v6.json\",\n  \"title\": \"Signups by region\",\n  \"data\": { \"name\": \"table\" },\n  \"mark\": { \"type\": \"bar\", \"tooltip\": true },\n  \"encoding\": {\n    \"x\": { \"field\": \"region\", \"type\": \"nominal\", \"title\": \"Region\" },\n    \"y\": { \"field\": \"signups\", \"type\": \"quantitative\", \"title\": \"Signups\" },\n    \"color\": { \"field\": \"region\", \"type\": \"nominal\", \"legend\": null }\n  }\n}\n",
  "Resources/config.json": "{\n  \"name\": \"Personal\",\n  \"version\": 1,\n  \"features\": {\n    \"canvas\": true,\n    \"search\": true\n  }\n}\n",
  "Resources/schema.yaml": "title: Sample schema\nversion: 1\nfields:\n  - name: id\n    type: text\n  - name: status\n    type: text\n",
